import{c as a,Q as t,j as s,m as o}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Семейства анализа","description":"","frontmatter":{},"headers":[],"relativePath":"ru/analysis.md","filePath":"ru/analysis.md","lastUpdated":null}'),i={name:"ru/analysis.md"};function d(c,e,r,l,n,p){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="семеиства-анализа" tabindex="-1">Семейства анализа <a class="header-anchor" href="#семеиства-анализа" aria-label="Permalink to &quot;Семейства анализа&quot;">​</a></h1><p>Эта страница документирует analysis outputs, используемые основным приложением. Используйте ее, чтобы решить, какую analysis job запускать перед затратой CPU или GPU time. Для отдельного инструмента разметки и обучения классификаторов см. <a href="./rhythm-lab.html">Rhythm Lab</a>.</p><h2 id="семеиства-анализа-1" tabindex="-1">Семейства анализа <a class="header-anchor" href="#семеиства-анализа-1" aria-label="Permalink to &quot;Семейства анализа&quot;">​</a></h2><p>Каждое семейство пишет разные SQLite data и поддерживает разный workflow:</p><table tabindex="0"><thead><tr><th>Семейство</th><th>Что делает</th><th>Когда использовать</th></tr></thead><tbody><tr><td>Sonara</td><td>Извлекает объяснимые playlist features: tempo, energy, loudness, rhythm и tonal summaries.</td><td>Нужен быстрый seed search, видимые feature controls или library filters.</td></tr><tr><td>MAEST</td><td>Предсказывает genre labels и сохраняет MAEST embeddings.</td><td>Нужны сгенерированные genre tags, review жанров, preset <code>syncopated</code> или classifier inputs.</td></tr><tr><td>MERT</td><td>Строит audio embeddings для seed-track similarity.</td><td>Нужен сценарий &quot;найти треки рядом с этим треком&quot; через audio model.</td></tr><tr><td>CLAP</td><td>Строит music audio embeddings и text vectors.</td><td>Нужен text-to-audio search по описательным prompts.</td></tr><tr><td>Promoted classifiers</td><td>Оценивает треки локальной моделью, обученной в Rhythm Lab.</td><td>Нужен переиспользуемый custom signal, например vocal presence, live instrumentation или другой profile-specific label.</td></tr></tbody></table><h3 id="sonara" tabindex="-1">Sonara <a class="header-anchor" href="#sonara" aria-label="Permalink to &quot;Sonara&quot;">​</a></h3><p>Sonara используется в playlist mode как быстрый explainable feature pass. Она сохраняет focused playlist features в <code>metadata_json.sonara_features</code> и имя модели в <code>metadata_json.sonara_model</code>.</p><p>Stored groups and keys:</p><ul><li>Core features: <code>bpm</code>, <code>beats</code>, <code>onset_frames</code>, <code>onset_density</code>, <code>n_beats</code>, <code>rms_mean</code>, <code>rms_max</code>, <code>loudness_lufs</code>, <code>dynamic_range_db</code>, <code>spectral_centroid_mean</code>, <code>zero_crossing_rate</code>, <code>duration_sec</code>.</li><li>Perceptual features: <code>energy</code>, <code>danceability</code>, <code>valence</code>, <code>acousticness</code>.</li><li>Musical key: <code>key</code>, <code>key_confidence</code>.</li><li>Tonal analysis: <code>predominant_chord</code>, <code>chord_change_rate</code>, <code>dissonance</code>.</li><li>Spectral features: <code>spectral_bandwidth_mean</code>, <code>spectral_rolloff_mean</code>, <code>spectral_flatness_mean</code>, <code>spectral_contrast_mean</code>, <code>mfcc_mean</code>, <code>chroma_mean</code>.</li></ul><p>Sonara BPM и key - анализированные значения, а не копии file tags. Приложение хранит raw Sonara key data и не выводит Camelot notation.</p><p>CLI и UI вызывают Sonara с <code>batch_size</code> как parallel track workers, а не как neural-network inference batch.</p><p>Запускайте Sonara рано, если не уверены, с чего начать. Это самое прозрачное семейство анализа: UI может напрямую показывать и смешивать его feature groups.</p><h3 id="maest" tabindex="-1">MAEST <a class="header-anchor" href="#maest" aria-label="Permalink to &quot;MAEST&quot;">​</a></h3><p>MAEST во время анализа пишет genre metadata и embeddings только в SQLite:</p><ul><li><code>metadata_json.maest_model</code></li><li><code>metadata_json.maest_genres</code></li><li><code>metadata_json.maest_syncopated_rhythm</code></li><li><code>embeddings.embedding_key = &quot;maest&quot;</code></li></ul><p>Adapter использует <code>maest-infer</code> с <code>discogs-maest-30s-pw-129e-519l</code>. Он анализирует до трех 30-second windows на track:</p><ul><li>offset 60 seconds;</li><li>window около 38 percent duration;</li><li>window около 72 percent duration.</li></ul><p>Impossible или duplicate windows clamped and deduplicated. Per-label activations усредняются по windows, затем top labels сохраняются. MAEST embedding rows усредняются по тем же windows и сохраняются под embedding key <code>maest</code>.</p><p>MAEST analysis сам не изменяет аудиофайлы. Отдельное genre-save action позже может записать сохраненные MAEST labels в standard audio genre tags. Флаг <code>maest_syncopated_rhythm</code> выводится из сохраненных MAEST genres и используется library preset <code>syncopated</code>.</p><p>Запускайте MAEST перед genre writing или preset <code>syncopated</code>. Проверяйте labels перед записью в файлы: analysis database-only, но tag writing - явная мутация аудиофайлов.</p><h3 id="mert" tabindex="-1">MERT <a class="header-anchor" href="#mert" aria-label="Permalink to &quot;MERT&quot;">​</a></h3><p>MERT строит audio-to-audio embeddings под embedding key <code>mert</code>.</p><p>Default model:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>m-a-p/MERT-v1-95M</span></span></code></pre></div><p>MERT search использует только MERT vectors. Он не смешивает Sonara features или CLAP vectors.</p><p>Запускайте MERT, когда seed-track similarity важнее explainable controls. Search results зависят от существующих MERT embeddings, поэтому newly scanned tracks нужно проанализировать, прежде чем они появятся в полезных MERT results.</p><h3 id="clap" tabindex="-1">CLAP <a class="header-anchor" href="#clap" aria-label="Permalink to &quot;CLAP&quot;">​</a></h3><p>CLAP строит music-focused audio embeddings под embedding key <code>clap</code> и создает text vectors для text-to-audio search.</p><p>Active checkpoint:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lukewys/laion_clap/music_audioset_epoch_15_esc_90.14.pt</span></span></code></pre></div><p>Text search требует CLAP audio embeddings, созданных тем же CLAP checkpoint.</p><p>Запускайте CLAP, когда нужно искать по mood, instrumentation, energy или другому описательному языку. Четкие concrete prompts обычно работают лучше, чем одиночные genre words.</p><h3 id="promoted-classifiers" tabindex="-1">Promoted classifiers <a class="header-anchor" href="#promoted-classifiers" aria-label="Permalink to &quot;Promoted classifiers&quot;">​</a></h3><p>Promoted classifiers - локальные classifier profiles, а не audio-analysis models, которые сами декодируют files. Они оценивают tracks из уже сохраненных analysis outputs:</p><ul><li>SONARA playlist features из <code>metadata_json.sonara_features</code>;</li><li>MERT embeddings из <code>embeddings.embedding_key = &quot;mert&quot;</code>;</li><li>MAEST embeddings из <code>embeddings.embedding_key = &quot;maest&quot;</code>.</li></ul><p>Tracks без любого из этих inputs пропускаются classifier job. Scores сохраняются в <code>track_classifier_scores</code> под profile classifier key.</p><p>Используйте promoted classifiers после обучения и promotion профиля в Rhythm Lab. Лучше всего они подходят для персональных concepts библиотеки, которые трудно описать generic genre label или одним similarity seed.</p><p>Стабильные model locations используют profile artifact prefix:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>models/classifiers/&lt;artifact-prefix&gt;/model.joblib</span></span></code></pre></div><p>Эти файлы создаются вне основного приложения командой promotion из Rhythm Lab:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tools\\rhythm</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lab\\rhythm_lab_cli.py promote </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">profile live_instrumentation</span></span></code></pre></div><p>Promoted <code>model.joblib</code> и <code>model.json</code> - локальные artifacts, игнорируемые git. Исходные Rhythm Lab training artifacts остаются в classifier-specific lab workspace:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tools/rhythm-lab/artifacts/&lt;artifact-prefix&gt;/</span></span></code></pre></div><p>Promoted metadata генерируется из Rhythm Lab profile и model artifact: <code>classifier_key</code>, profile name, profile type, labels, feature set, source artifact и training label counts. Rhythm Lab training metrics используют одну profile-neutral shape для всех profiles (<code>positive_*</code> metrics и <code>label_order</code>) вместо classifier-specific metric aliases.</p><p>О profile management, labeling, training, prediction, promotion, archive и delete workflows в Rhythm Lab см. <a href="./rhythm-lab.html">Rhythm Lab</a>.</p><p>User-facing score - classifier probability для positive training label профиля. Поскольку UI displays могут округлять probabilities, значение <code>1.0000</code> может быть немного ниже математического <code>1.0</code>. Для практической фильтрации используйте thresholds вроде <code>0.99</code>, <code>0.95</code> или <code>0.90</code>, а не точное <code>1.0</code>.</p>',46)])])}const u=a(i,[["render",d]]);export{m as __pageData,u as default};
